// generated by sprint 61-1 — Apple notarization utilities

import { type NotarizationConfig } from "./types";

export interface NotarizeResult {
  readonly submitted: boolean;
  readonly requestUuid: string | null;
  readonly status: "pending" | "accepted" | "rejected" | "error";
  readonly errors: string[];
}

export interface StapleResult {
  readonly stapled: boolean;
  readonly path: string;
  readonly errors: string[];
}

export function buildNotarizeSubmitCommand(
  dmgPath: string,
  config: NotarizationConfig
): string[] {
  return [
    "xcrun",
    "notarytool",
    "submit",
    dmgPath,
    "--apple-id",
    config.appleId,
    "--team-id",
    config.teamId,
    "--password",
    `\${${config.passwordEnvVar}}`,
    "--wait",
    "--timeout",
    "30m",
  ];
}

export function buildNotarizeStatusCommand(requestUuid: string): string[] {
  return ["xcrun", "notarytool", "info", requestUuid];
}

export function buildNotarizeLogCommand(requestUuid: string): string[] {
  return ["xcrun", "notarytool", "log", requestUuid];
}

export function buildStapleCommand(path: string): string[] {
  return ["xcrun", "stapler", "staple", path];
}

export function buildStapleValidateCommand(path: string): string[] {
  return ["xcrun", "stapler", "validate", path];
}

export function resolveNotarizationConfigFromEnv(): NotarizationConfig | null {
  const appleId =
    process.env.APPLE_ID ?? process.env.NOTARIZE_APPLE_ID ?? null;
  const teamId =
    process.env.APPLE_TEAM_ID ?? process.env.NOTARIZE_TEAM_ID ?? null;

  if (!appleId || !teamId) {
    return null;
  }

  return {
    appleId,
    teamId,
    passwordEnvVar:
      process.env.NOTARIZE_PASSWORD_VAR ?? "APPLE_APP_SPECIFIC_PASSWORD",
  };
}

export function buildFullNotarizationPipeline(
  dmgPath: string,
  config: NotarizationConfig
): { step: string; command: string[] }[] {
  return [
    {
      step: "submit",
      command: buildNotarizeSubmitCommand(dmgPath, config),
    },
    {
      step: "staple",
      command: buildStapleCommand(dmgPath),
    },
    {
      step: "validate",
      command: buildStapleValidateCommand(dmgPath),
    },
  ];
}
